import React, { useRef, useEffect, useState } from 'react';
import { useWebRTC } from '../../hooks/useWebRTC';
import { ChatWindow } from '../Chat/ChatWindow';
import { VideoGrid } from '../Video/VideoGrid';

interface BroadcasterViewProps {
  roomId: string;
  userId: string;
  onLeave: () => void;
}

export const BroadcasterView: React.FC<BroadcasterViewProps> = ({ roomId, userId, onLeave }) => {
  const localVideoRef = useRef<HTMLVideoElement>(null);
  const [isStreaming, setIsStreaming] = useState(false);

  const { localStream, remoteStreams, isConnected, error, isLocalMuted, startMedia, stopMedia, leave, toggleLocalMute, muteParticipant, signalingClient } = useWebRTC({
    roomId,
    role: 'broadcaster',
    userId,
  });

  useEffect(() => {
    if (localStream && localVideoRef.current) {
      localVideoRef.current.srcObject = localStream;
    }
  }, [localStream]);

  const handleStartMedia = async () => {
    try {
      await startMedia();
      setIsStreaming(true);
    } catch (err) {
      console.error('Failed to start media:', err);
    }
  };

  const handleStopMedia = () => {
    stopMedia();
    setIsStreaming(false);
  };

  const handleLeave = () => {
    stopMedia();
    leave();
    onLeave();
  };

  return (
    <div style={styles.container}>
      <div style={styles.header}>
        <h2>Video Conference - Host</h2>
        <div style={styles.status}>
          {isConnected ? (
            <span style={styles.statusConnected}>● Connected</span>
          ) : (
            <span style={styles.statusDisconnected}>● Disconnected</span>
          )}
        </div>
      </div>

      {error && <div style={styles.error}>{error}</div>}

      <div style={styles.mainContent}>
        <div style={styles.videoSection}>
          {/* Local video (large) */}
          <div style={styles.localVideoContainer}>
            <video
              ref={localVideoRef}
              autoPlay
              muted
              playsInline
              style={styles.localVideo}
            />
            {!isStreaming && (
              <div style={styles.overlay}>
                <p>Click "Start Camera" to begin</p>
              </div>
            )}
            <div style={styles.localLabel}>You (Host)</div>
          </div>

          {/* Remote participants grid */}
          {remoteStreams.size > 0 && (
            <div style={styles.remoteSection}>
              <h3>Participants ({remoteStreams.size})</h3>
              <VideoGrid
                streams={remoteStreams}
                onMuteParticipant={muteParticipant}
                canMuteOthers={true}
              />
            </div>
          )}

          <div style={styles.controls}>
            {!isStreaming ? (
              <button onClick={handleStartMedia} style={styles.startButton}>
                Start Camera
              </button>
            ) : (
              <button onClick={handleStopMedia} style={styles.stopButton}>
                Stop Camera
              </button>
            )}
            {isStreaming && (
              <button
                onClick={toggleLocalMute}
                style={isLocalMuted ? styles.unmuteMicButton : styles.muteMicButton}
              >
                {isLocalMuted ? '🔊 Unmute' : '🔇 Mute'}
              </button>
            )}
            <button onClick={handleLeave} style={styles.leaveButton}>
              Leave Room
            </button>
          </div>

          <div style={styles.info}>
            <p><strong>Room ID:</strong> {roomId}</p>
            <p><strong>Participants:</strong> {remoteStreams.size + 1}</p>
          </div>
        </div>

        <div style={styles.chatSection}>
          <ChatWindow
            roomId={roomId}
            userId={userId}
            userRole="broadcaster"
            signalingClient={signalingClient}
          />
        </div>
      </div>
    </div>
  );
};

const styles: { [key: string]: React.CSSProperties } = {
  container: {
    padding: '20px',
    maxWidth: '1400px',
    margin: '0 auto',
  },
  header: {
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center',
    marginBottom: '20px',
  },
  status: {
    fontSize: '14px',
  },
  statusConnected: {
    color: 'green',
  },
  statusDisconnected: {
    color: 'red',
  },
  mainContent: {
    display: 'grid',
    gridTemplateColumns: '1fr 350px',
    gap: '20px',
  },
  videoSection: {
    display: 'flex',
    flexDirection: 'column',
    gap: '20px',
  },
  localVideoContainer: {
    position: 'relative',
    backgroundColor: '#000',
    borderRadius: '8px',
    overflow: 'hidden',
    aspectRatio: '16/9',
  },
  localVideo: {
    width: '100%',
    height: '100%',
    objectFit: 'cover',
  },
  localLabel: {
    position: 'absolute',
    bottom: '10px',
    left: '10px',
    backgroundColor: 'rgba(0, 0, 0, 0.6)',
    color: '#ffc107',
    padding: '4px 8px',
    borderRadius: '4px',
    fontSize: '12px',
    fontWeight: 'bold',
  },
  overlay: {
    position: 'absolute',
    top: 0,
    left: 0,
    right: 0,
    bottom: 0,
    backgroundColor: 'rgba(0, 0, 0, 0.7)',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    color: 'white',
    fontSize: '18px',
  },
  remoteSection: {
    marginTop: '10px',
  },
  controls: {
    display: 'flex',
    gap: '10px',
  },
  startButton: {
    flex: 1,
    padding: '15px',
    border: 'none',
    borderRadius: '4px',
    cursor: 'pointer',
    backgroundColor: '#28a745',
    color: 'white',
    fontSize: '16px',
    fontWeight: 'bold',
  },
  stopButton: {
    flex: 1,
    padding: '15px',
    border: 'none',
    borderRadius: '4px',
    cursor: 'pointer',
    backgroundColor: '#dc3545',
    color: 'white',
    fontSize: '16px',
    fontWeight: 'bold',
  },
  leaveButton: {
    flex: 1,
    padding: '15px',
    border: 'none',
    borderRadius: '4px',
    cursor: 'pointer',
    backgroundColor: '#6c757d',
    color: 'white',
    fontSize: '16px',
    fontWeight: 'bold',
  },
  info: {
    padding: '15px',
    backgroundColor: '#f8f9fa',
    borderRadius: '4px',
  },
  error: {
    color: 'red',
    padding: '10px',
    marginBottom: '10px',
    backgroundColor: '#fee',
    borderRadius: '4px',
  },
  chatSection: {
    minHeight: '400px',
  },
};
